62: /**
63:  * This is a recommended base class for all of the {@link SinkFunction} that intend to implement
64:  * exactly-once semantic. It does that by implementing two phase commit algorithm on top of the
65:  * {@link CheckpointedFunction} and {@link CheckpointListener}. User should provide custom {@code
66:  * TXN} (transaction handle) and implement abstract methods handling this transaction handle.
67:  *
68:  * @param <IN> Input type for {@link SinkFunction}.
69:  * @param <TXN> Transaction to store all of the information required to handle a transaction.
70:  * @param <CONTEXT> Context that will be shared across all invocations for the given {@link
71:  *     TwoPhaseCommitSinkFunction} instance. Context is created once
72:  * @deprecated This interface will be removed in future versions. Use the new {@link
73:  *     org.apache.flink.api.connector.sink2.Sink} interface instead.
74:  */
75: @Internal
76: public abstract class TwoPhaseCommitSinkFunction<IN, TXN, CONTEXT> extends RichSinkFunction<IN>
77:         implements CheckpointedFunction, CheckpointListener {
78: 
79:     private static final Logger LOG = LoggerFactory.getLogger(TwoPhaseCommitSinkFunction.class);
80: 
81:     protected final LinkedHashMap<Long, TransactionHolder<TXN>> pendingCommitTransactions =
82:             new LinkedHashMap<>();
83: 
84:     protected transient Optional<CONTEXT> userContext;
85: 
86:     protected transient ListState<State<TXN, CONTEXT>> state;
87: 
88:     private final Clock clock;
89: 
90:     private final ListStateDescriptor<State<TXN, CONTEXT>> stateDescriptor;
91: 
92:     /**
93:      * Current Transaction Holder, including two states: 1. Normal Transaction: created when a new
94:      * snapshot is taken during normal task running 2. null: After task/function is finished.
95:      */
96:     @Nullable private TransactionHolder<TXN> currentTransactionHolder;
97: 
98:     /** Specifies the maximum time a transaction should remain open. */
99:     private long transactionTimeout = Long.MAX_VALUE;
100: 
101:     /**
102:      * If true, any exception thrown in {@link #recoverAndCommit(Object)} will be caught instead of
103:      * propagated.
104:      */
105:     private boolean ignoreFailuresAfterTransactionTimeout;
106: 
107:     /**
108:      * If a transaction's elapsed time reaches this percentage of the transactionTimeout, a warning
109:      * message will be logged. Value must be in range [0,1]. Negative value disables warnings.
110:      */
111:     private double transactionTimeoutWarningRatio = -1;
112: 
113:     /** Whether this sink function as well as its task is finished. */
114:     private boolean finished = false;
115: 
116:     /**
117:      * Use default {@link ListStateDescriptor} for internal state serialization. Helpful utilities
118:      * for using this constructor are {@link TypeInformation#of(Class)}, {@link
119:      * org.apache.flink.api.common.typeinfo.TypeHint} and {@link TypeInformation#of(TypeHint)}.
120:      * Example:
121:      *
122:      * <pre>{@code
123:      * TwoPhaseCommitSinkFunction(TypeInformation.of(new TypeHint<State<TXN, CONTEXT>>() {}));
124:      * }</pre>
125:      *
126:      * @param transactionSerializer {@link TypeSerializer} for the transaction type of this sink
127:      * @param contextSerializer {@link TypeSerializer} for the context type of this sink
128:      */
129:     public TwoPhaseCommitSinkFunction(
130:             TypeSerializer<TXN> transactionSerializer, TypeSerializer<CONTEXT> contextSerializer) {
131:         this(transactionSerializer, contextSerializer, Clock.systemUTC());
132:     }
133: 
134:     @VisibleForTesting
135:     TwoPhaseCommitSinkFunction(
136:             TypeSerializer<TXN> transactionSerializer,
137:             TypeSerializer<CONTEXT> contextSerializer,
138:             Clock clock) {
139:         this.stateDescriptor =
140:                 new ListStateDescriptor<>(
141:                         "state", new StateSerializer<>(transactionSerializer, contextSerializer));
142:         this.clock = clock;
143:     }
144: 
145:     protected Optional<CONTEXT> initializeUserContext() {
146:         return Optional.empty();
147:     }
148: 
149:     protected Optional<CONTEXT> getUserContext() {
150:         return userContext;
151:     }
152: 
153:     @Nullable
154:     protected TXN currentTransaction() {
155:         return currentTransactionHolder == null ? null : currentTransactionHolder.handle;
156:     }
157: 
158:     @Nonnull
159:     protected Stream<Map.Entry<Long, TXN>> pendingTransactions() {
160:         return pendingCommitTransactions.entrySet().stream()
161:                 .map(e -> new AbstractMap.SimpleEntry<>(e.getKey(), e.getValue().handle));
162:     }
163: 
164:     // ------ methods that should be implemented in child class to support two phase commit
165:     // algorithm ------
166: 
167:     /** Write value within a transaction. */
168:     protected abstract void invoke(TXN transaction, IN value, Context context) throws Exception;
169: 
170:     /**
171:      * Method that starts a new transaction.
172:      *
173:      * @return newly created transaction.
174:      */
175:     protected abstract TXN beginTransaction() throws Exception;
176: 
177:     /**
178:      * Pre commit previously created transaction. Pre commit must make all of the necessary steps to
179:      * prepare the transaction for a commit that might happen in the future. After this point the
180:      * transaction might still be aborted, but underlying implementation must ensure that commit
181:      * calls on already pre committed transactions will always succeed.
182:      *
183:      * <p>Usually implementation involves flushing the data.
184:      */
185:     protected abstract void preCommit(TXN transaction) throws Exception;
186: 
187:     /**
188:      * Commit a pre-committed transaction. If this method fail, Flink application will be restarted
189:      * and {@link TwoPhaseCommitSinkFunction#recoverAndCommit(Object)} will be called again for the
190:      * same transaction.
191:      */
192:     protected abstract void commit(TXN transaction);
193: 
194:     /**
195:      * Invoked on recovered transactions after a failure. User implementation must ensure that this
196:      * call will eventually succeed. If it fails, Flink application will be restarted and it will be
197:      * invoked again. If it does not succeed eventually, a data loss will occur. Transactions will
198:      * be recovered in an order in which they were created.
199:      */
200:     protected void recoverAndCommit(TXN transaction) {
201:         commit(transaction);
202:     }
203: 
204:     /** Abort a transaction. */
205:     protected abstract void abort(TXN transaction);
206: 
207:     /** Abort a transaction that was rejected by a coordinator after a failure. */
208:     protected void recoverAndAbort(TXN transaction) {
209:         abort(transaction);
210:     }
211: 
212:     /**
213:      * Callback for subclasses which is called after restoring (each) user context.
214:      *
215:      * @param handledTransactions transactions which were already committed or aborted and do not
216:      *     need further handling
217:      */
218:     protected void finishRecoveringContext(Collection<TXN> handledTransactions) {}
219: 
220:     /**
221:      * This method is called at the end of data processing.
222:      *
223:      * <p>The method is expected to flush all remaining buffered data. Exceptions will cause the
224:      * pipeline to be recognized as failed, because the last data items are not processed properly.
225:      * You may use this method to flush remaining buffered elements in the state into the current
226:      * transaction which will be committed in the last checkpoint.
227:      */
228:     protected void finishProcessing(@Nullable TXN transaction) {}
229: 
230:     // ------ entry points for above methods implementing {@CheckPointedFunction} and
231:     // {@CheckpointListener} ------
232: 
233:     /** This should not be implemented by subclasses. */
234:     @Override
235:     public final void invoke(IN value) throws Exception {}
236: 
237:     @Override
238:     public final void invoke(IN value, Context context) throws Exception {
239:         TXN currentTransaction = currentTransaction();
240:         checkNotNull(
241:                 currentTransaction,
242:                 "Two phase commit sink function with null transaction should not be invoked! ");
243:         invoke(currentTransaction, value, context);
244:     }
245: 
246:     @Override
247:     public final void finish() throws Exception {
248:         finished = true;
249:         finishProcessing(currentTransaction());
250:     }
251: 
252:     @Override
253:     public final void notifyCheckpointComplete(long checkpointId) throws Exception {
254:         // the following scenarios are possible here
255:         //
256:         //  (1) there is exactly one transaction from the latest checkpoint that
257:         //      was triggered and completed. That should be the common case.
258:         //      Simply commit that transaction in that case.
259:         //
260:         //  (2) there are multiple pending transactions because one previous
261:         //      checkpoint was skipped. That is a rare case, but can happen
262:         //      for example when:
263:         //
264:         //        - the master cannot persist the metadata of the last
265:         //          checkpoint (temporary outage in the storage system) but
266:         //          could persist a successive checkpoint (the one notified here)
267:         //
268:         //        - other tasks could not persist their status during
269:         //          the previous checkpoint, but did not trigger a failure because they
270:         //          could hold onto their state and could successfully persist it in
271:         //          a successive checkpoint (the one notified here)
272:         //
273:         //      In both cases, the prior checkpoint never reach a committed state, but
274:         //      this checkpoint is always expected to subsume the prior one and cover all
275:         //      changes since the last successful one. As a consequence, we need to commit
276:         //      all pending transactions.
277:         //
278:         //  (3) Multiple transactions are pending, but the checkpoint complete notification
279:         //      relates not to the latest. That is possible, because notification messages
280:         //      can be delayed (in an extreme case till arrive after a succeeding checkpoint
281:         //      was triggered) and because there can be concurrent overlapping checkpoints
282:         //      (a new one is started before the previous fully finished).
283:         //
284:         // ==> There should never be a case where we have no pending transaction here
285:         //
286: 
287:         Iterator<Map.Entry<Long, TransactionHolder<TXN>>> pendingTransactionIterator =
288:                 pendingCommitTransactions.entrySet().iterator();
289:         Throwable firstError = null;
290: 
291:         while (pendingTransactionIterator.hasNext()) {
292:             Map.Entry<Long, TransactionHolder<TXN>> entry = pendingTransactionIterator.next();
293:             Long pendingTransactionCheckpointId = entry.getKey();
294:             TransactionHolder<TXN> pendingTransaction = entry.getValue();
295:             if (pendingTransactionCheckpointId > checkpointId) {
296:                 continue;
297:             }
298: 
299:             LOG.info(
300:                     "{} - checkpoint {} complete, committing transaction {} from checkpoint {}",
301:                     name(),
302:                     checkpointId,
303:                     pendingTransaction,
304:                     pendingTransactionCheckpointId);
305: 
306:             logWarningIfTimeoutAlmostReached(pendingTransaction);
307:             try {
308:                 commit(pendingTransaction.handle);
309:             } catch (Throwable t) {
310:                 if (firstError == null) {
311:                     firstError = t;
312:                 }
313:             }
314: 
315:             LOG.debug("{} - committed checkpoint transaction {}", name(), pendingTransaction);
316: 
317:             pendingTransactionIterator.remove();
318:         }
319: 
320:         if (firstError != null) {
321:             throw new FlinkRuntimeException(
322:                     "Committing one of transactions failed, logging first encountered failure",
323:                     firstError);
324:         }
325:     }
