330:     @Override
331:     public void snapshotState(FunctionSnapshotContext context) throws Exception {
332:         // this is like the pre-commit of a 2-phase-commit transaction
333:         // we are ready to commit and remember the transaction
334: 
335:         long checkpointId = context.getCheckpointId();
336:         LOG.debug(
337:                 "{} - checkpoint {} triggered, flushing transaction '{}'",
338:                 name(),
339:                 context.getCheckpointId(),
340:                 currentTransactionHolder);
341: 
342:         if (currentTransactionHolder != null) {
343:             preCommit(currentTransactionHolder.handle);
344:             pendingCommitTransactions.put(checkpointId, currentTransactionHolder);
345:             LOG.debug("{} - stored pending transactions {}", name(), pendingCommitTransactions);
346:         }
347: 
348:         // no need to start new transactions after sink function is closed (no more input data)
349:         if (!finished) {
350:             currentTransactionHolder = beginTransactionInternal();
351:         } else {
352:             currentTransactionHolder = null;
353:         }
354:         LOG.debug("{} - started new transaction '{}'", name(), currentTransactionHolder);
355: 
356:         state.update(
357:                 Collections.singletonList(
358:                         new State<>(
359:                                 this.currentTransactionHolder,
360:                                 new ArrayList<>(pendingCommitTransactions.values()),
361:                                 userContext)));
362:     }
