429:     /**
430:      * This method must be the only place to call {@link #beginTransaction()} to ensure that the
431:      * {@link TransactionHolder} is created at the same time.
432:      */
433:     private TransactionHolder<TXN> beginTransactionInternal() throws Exception {
434:         return new TransactionHolder<>(beginTransaction(), clock.millis());
435:     }
436: 
437:     /**
438:      * This method must be the only place to call {@link #recoverAndCommit(Object)} to ensure that
439:      * the configuration parameters {@link #transactionTimeout} and {@link
440:      * #ignoreFailuresAfterTransactionTimeout} are respected.
441:      */
442:     private void recoverAndCommitInternal(TransactionHolder<TXN> transactionHolder) {
443:         try {
444:             logWarningIfTimeoutAlmostReached(transactionHolder);
445:             recoverAndCommit(transactionHolder.handle);
446:         } catch (final Exception e) {
447:             final long elapsedTime = clock.millis() - transactionHolder.transactionStartTime;
448:             if (ignoreFailuresAfterTransactionTimeout && elapsedTime > transactionTimeout) {
449:                 LOG.error(
450:                         "Error while committing transaction {}. "
451:                                 + "Transaction has been open for longer than the transaction timeout ({})."
452:                                 + "Commit will not be attempted again. Data loss might have occurred.",
453:                         transactionHolder.handle,
454:                         transactionTimeout,
455:                         e);
456:             } else {
457:                 throw e;
458:             }
459:         }
460:     }
461: 
462:     private void logWarningIfTimeoutAlmostReached(TransactionHolder<TXN> transactionHolder) {
463:         final long elapsedTime = transactionHolder.elapsedTime(clock);
464:         if (transactionTimeoutWarningRatio >= 0
465:                 && elapsedTime > transactionTimeout * transactionTimeoutWarningRatio) {
466:             LOG.warn(
467:                     "Transaction {} has been open for {} ms. "
468:                             + "This is close to or even exceeding the transaction timeout of {} ms.",
469:                     transactionHolder.handle,
470:                     elapsedTime,
471:                     transactionTimeout);
472:         }
473:     }
