487:     /**
488:      * Sets the transaction timeout. Setting only the transaction timeout has no effect in itself.
489:      *
490:      * @param transactionTimeout The transaction timeout in ms.
491:      * @see #ignoreFailuresAfterTransactionTimeout()
492:      * @see #enableTransactionTimeoutWarnings(double)
493:      */
494:     protected TwoPhaseCommitSinkFunction<IN, TXN, CONTEXT> setTransactionTimeout(
495:             long transactionTimeout) {
496:         checkArgument(transactionTimeout >= 0, "transactionTimeout must not be negative");
497:         this.transactionTimeout = transactionTimeout;
498:         return this;
499:     }
500: 
501:     /**
502:      * If called, the sink will only log but not propagate exceptions thrown in {@link
503:      * #recoverAndCommit(Object)} if the transaction is older than a specified transaction timeout.
504:      * The start time of an transaction is determined by {@link System#currentTimeMillis()}. By
505:      * default, failures are propagated.
506:      */
507:     protected TwoPhaseCommitSinkFunction<IN, TXN, CONTEXT> ignoreFailuresAfterTransactionTimeout() {
508:         this.ignoreFailuresAfterTransactionTimeout = true;
509:         return this;
510:     }
511: 
512:     /**
513:      * Enables logging of warnings if a transaction's elapsed time reaches a specified ratio of the
514:      * <code>transactionTimeout</code>. If <code>warningRatio</code> is 0, a warning will be always
515:      * logged when committing the transaction.
516:      *
517:      * @param warningRatio A value in the range [0,1].
518:      * @return
519:      */
520:     protected TwoPhaseCommitSinkFunction<IN, TXN, CONTEXT> enableTransactionTimeoutWarnings(
521:             double warningRatio) {
522:         checkArgument(
523:                 warningRatio >= 0 && warningRatio <= 1, "warningRatio must be in range [0,1]");
524:         this.transactionTimeoutWarningRatio = warningRatio;
525:         return this;
526:     }
