927:                 TypeSerializerSnapshot<State<TXN, CONTEXT>> oldSerializerSnapshot) {
928:             if (!(oldSerializerSnapshot instanceof StateSerializerSnapshot)) {
929:                 return OuterSchemaCompatibility.INCOMPATIBLE;
930:             }
931: 
932:             StateSerializerSnapshot<TXN, CONTEXT> oldStateSerializerSnapshot =
933:                     (StateSerializerSnapshot<TXN, CONTEXT>) oldSerializerSnapshot;
934:             if (supportsNullTransaction != oldStateSerializerSnapshot.supportsNullTransaction) {
935:                 return OuterSchemaCompatibility.COMPATIBLE_AFTER_MIGRATION;
936:             }
937: 
938:             return OuterSchemaCompatibility.COMPATIBLE_AS_IS;
939:         }
940: 
941:         @Override
942:         protected StateSerializer<TXN, CONTEXT> createOuterSerializerWithNestedSerializers(
943:                 TypeSerializer<?>[] nestedSerializers) {
944:             @SuppressWarnings("unchecked")
945:             final TypeSerializer<TXN> transactionSerializer =
946:                     (TypeSerializer<TXN>) nestedSerializers[0];
947: 
948:             @SuppressWarnings("unchecked")
949:             final TypeSerializer<CONTEXT> contextSerializer =
950:                     (TypeSerializer<CONTEXT>) nestedSerializers[1];
951: 
952:             return new StateSerializer<>(
953:                     transactionSerializer, contextSerializer, supportsNullTransaction);
954:         }
955: 
956:         @Override
957:         protected TypeSerializer<?>[] getNestedSerializers(
958:                 StateSerializer<TXN, CONTEXT> outerSerializer) {
959:             return new TypeSerializer<?>[] {
960:                 outerSerializer.transactionSerializer, outerSerializer.contextSerializer
961:             };
962:         }
963:     }
