19: package org.apache.flink.streaming.api.functions.timestamps;
20: 
21: import org.apache.flink.streaming.api.watermark.Watermark;
22: import org.apache.flink.streaming.runtime.operators.util.WatermarkStrategyWithPeriodicWatermarks;
23: 
24: import java.time.Duration;
25: 
26: /**
27:  * This is a {@link WatermarkStrategyWithPeriodicWatermarks} used to emit Watermarks that lag behind
28:  * the element with the maximum timestamp (in event time) seen so far by a fixed amount of time,
29:  * <code>
30:  * t_late</code>. This can help reduce the number of elements that are ignored due to lateness when
31:  * computing the final result for a given window, in the case where we know that elements arrive no
32:  * later than <code>t_late</code> units of time after the watermark that signals that the system
33:  * event-time has advanced past their (event-time) timestamp.
34:  */
35: public abstract class BoundedOutOfOrdernessTimestampExtractor<T>
36:         implements WatermarkStrategyWithPeriodicWatermarks<T> {
37: 
38:     private static final long serialVersionUID = 1L;
39: 
40:     /** The current maximum timestamp seen so far. */
41:     private long currentMaxTimestamp;
42: 
43:     /** The timestamp of the last emitted watermark. */
44:     private long lastEmittedWatermark = Long.MIN_VALUE;
45: 
46:     /**
47:      * The (fixed) interval between the maximum seen timestamp seen in the records and that of the
48:      * watermark to be emitted.
49:      */
50:     private final long maxOutOfOrderness;
51: 
52:     public BoundedOutOfOrdernessTimestampExtractor(Duration maxOutOfOrderness) {
53:         if (maxOutOfOrderness.isNegative()) {
54:             throw new IllegalArgumentException(
55:                     String.format(
56:                             "Tried to set the maximum allowed lateness to %s. This parameter cannot be negative.",
57:                             maxOutOfOrderness));
58:         }
59: 
60:         this.maxOutOfOrderness = maxOutOfOrderness.toMillis();
61:         this.currentMaxTimestamp = Long.MIN_VALUE + this.maxOutOfOrderness;
62:     }
63: 
64:     public long getMaxOutOfOrdernessInMillis() {
65:         return maxOutOfOrderness;
66:     }
67: 
68:     /**
69:      * Extracts the timestamp from the given element.
70:      *
71:      * @param element The element that the timestamp is extracted from.
72:      * @return The new timestamp.
73:      */
74:     public abstract long extractTimestamp(T element);
75: 
76:     @Override
77:     public final Watermark getCurrentWatermark() {
78:         // this guarantees that the watermark never goes backwards.
79:         long potentialWM = currentMaxTimestamp - maxOutOfOrderness;
80:         if (potentialWM >= lastEmittedWatermark) {
81:             lastEmittedWatermark = potentialWM;
82:         }
83:         return new Watermark(lastEmittedWatermark);
84:     }
85: 
86:     @Override
87:     public final long extractTimestamp(T element, long previousElementTimestamp) {
88:         long timestamp = extractTimestamp(element);
89:         if (timestamp > currentMaxTimestamp) {
90:             currentMaxTimestamp = timestamp;
91:         }
92:         return timestamp;
93:     }
94: }
